  42: { p:4.5,  d2:39.077, d3:37.129, As:1121,  dw:65.0, dh:45.0 },
};

// ボルト強度区分（JIS B 1051 / ISO 898-1・ISO 3506）
const BOLT_GRADES = {
  '4.6':   { Sy: 240,  Su: 400  },
  '4.8':   { Sy: 340,  Su: 420  },
  '8.8':   { Sy: 660,  Su: 830  },
  '10.9':  { Sy: 940,  Su: 1040 },
  '12.9':  { Sy: 1100, Su: 1220 },
  'A2-70': { Sy: 450,  Su: 700  },
  'A4-70': { Sy: 450,  Su: 700  },
  'A4-80': { Sy: 600,  Su: 800  },
  'A2017': { Sy: 275,  Su: 440  },
  'A5052': { Sy: 215,  Su: 265  },
  'A6061': { Sy: 275,  Su: 310  },
  'C3604': { Sy: 300,  Su: 400  },
};

// 被締結材（許容せん断強度 tau、許容面圧 bearing）
const CLAMPED_MATERIALS = {
  spcc:      { tau: 340, bearing: 220, name: '鋼板 SPCC'    },
  steel:     { tau: 400, bearing: 220, name: '鋼 SS400'     },
  s45c:      { tau: 690, bearing: 380, name: '鋼 S45C'      },
  sus304:    { tau: 520, bearing: 185, name: 'SUS304'       },
  aluminum:  { tau: 310, bearing: 60,  name: 'アルミ合金'   },
  cast_iron: { tau: 200, bearing: 120, name: '鋳鉄 FC200'   },
  brass:     { tau: 390, bearing: 100, name: '真鍮'         },
  resin:     { tau: 65,  bearing: 30,  name: 'エンプラ'     },
};

// 摩擦条件（ねじ面 mt、座面 mw）
const FRICTION_MAP = {
  dry:    { mt: 0.15, mw: 0.15, label: 'μ=0.15 乾燥'  },
  lube:   { mt: 0.10, mw: 0.10, label: 'μ=0.10 潤滑'  },
  grease: { mt: 0.08, mw: 0.08, label: 'μ=0.08 グリス' },
};

// 軟質材（座面陥没・山せん断が問題になりやすい材料）
const SOFT_MATERIALS = new Set(['aluminum', 'cast_iron', 'brass', 'resin']);

/**
 * ボルト締付トルク計算（JIS B 1083）
 *
 * @param {object} params
 * @param {number} params.d        - ボルト呼び径 (mm) 例: 10
 * @param {string} params.grade    - 強度区分キー 例: '10.9'
 * @param {string} params.partMat  - 被締結材キー 例: 'aluminum'
 * @param {string} params.mu       - 摩擦条件キー 例: 'dry'
 * @param {number} [params.sf=1.5] - 安全率
 * @param {number} [params.dep=1.0]- ねじ込み深さ係数（×d）
 *
 * @returns {BoltResult}
 *   error        {string|null}  バリデーションエラー（null = 正常）
 *   K            {number}       トルク係数（無次元）
 *   Fy           {number}       降伏軸力 (kN)
 *   T_lim        {number}       限界トルク (N·m)
 *   T_jis        {number}       JIS標準推奨トルク = T_lim/sf (N·m)
 *   T_rec        {number}       推奨締付トルク（被締結材を考慮） (N·m)
 *   T_range      {object}       許容範囲 { min, max } (N·m) ±10%
 *   failModes    {object[]}     破損モード一覧 [{name, F, T}] 昇順
 *   dominant     {string}       支配的破損モード名
 *   isMaterialLimit {boolean}   被締結材強度で制限されているか
 *   warnings     {string[]}     警告メッセージ
 */
function boltCalc(params) {
  const { d, grade: grK, partMat: partMatKey, mu: muKey, sf = 1.5, dep = 1.0 } = params;

  const b = BOLT_DATA[d];
  if (!b) return { error: `ボルト径 M${d} は対応範囲外です（M3〜M42）` };
  const gr = BOLT_GRADES[grK];
  if (!gr) return { error: `強度区分 "${grK}" はデータベースにありません` };
  const clB = CLAMPED_MATERIALS[partMatKey];
  if (!clB) return { error: `被締結材 "${partMatKey}" はデータベースにありません` };
  const muData = FRICTION_MAP[muKey];
  if (!muData) return { error: `摩擦条件 "${muKey}" はデータベースにありません` };

  const { mt, mw } = muData;

  // JIS B 1083 式(2)：トルク係数 K
  const Db  = (b.dw + b.dh) / 2;
  const K   = b.p / (2 * Math.PI * d) + 0.577 * mt * b.d2 / d + mw * Db / (2 * d);
  const Knd = K * d;

  // JIS B 1083 式(7)：降伏軸力 Fy (kN)
  const At       = b.p / (2 * Math.PI) + 0.577 * mt * b.d2;
  const dAs      = Math.sqrt(4 * b.As / Math.PI);
  const Fy_denom = 1 + 3 * Math.pow(3 / dAs * At, 2);
  const Fy       = gr.Sy * b.As / Math.sqrt(Fy_denom) / 1000;

  // JIS B 1083 式(8)：限界トルク T_lim (N·m)
  const T_lim = Knd * Fy;

  // 破損モード別限界軸力 (kN)
  const nTh  = Math.max(1, (dep * d - 0.5 * b.p) / b.p);   // 有効ねじ山数
  const bArea = (Math.PI / 4) * (b.dw * b.dw - b.dh * b.dh);
  const Fbrk = gr.Su * b.As / 1000;                                    // ボルト破断
  const Fstr = clB.tau * Math.PI * d * 0.5 * b.p * nTh * 0.577 / 1000; // 山せん断
  const FbA  = clB.bearing * bArea / 1000;                             // 座面陥没

  const failModes = [
    { name: 'ボルト破断', F: Fbrk },
    { name: '山せん断',   F: Fstr },
    { name: '座面陥没',   F: FbA  },
  ].sort((a, b) => a.F - b.F).map(fm => ({ name: fm.name, F: fm.F, T: fm.F * Knd }));

  const dominant = failModes[0];
  const T_jis = T_lim / sf;
  const isSoft = SOFT_MATERIALS.has(partMatKey);
  const T_mat  = dominant.T / sf;
  const T_rec  = isSoft ? Math.min(T_jis, T_mat) : T_jis;
  const isMaterialLimit = isSoft && T_mat < T_jis;

  const warnings = [];
  if (isMaterialLimit) {
    if (dominant.name === '山せん断') {
      warnings.push(`相手部材の山せん断強度により制限（JIS標準 ${T_jis.toFixed(2)} N·m → ${T_rec.toFixed(2)} N·m）`);
      warnings.push('ねじ込み深さを増やすか、相手材の強化を推奨');
    } else if (dominant.name === '座面陥没') {
      warnings.push(`相手部材の許容面圧により制限（JIS標準 ${T_jis.toFixed(2)} N·m → ${T_rec.toFixed(2)} N·m）`);
    }
  }

  return {
    error: null,
    // 入力
    d, grade: grK, partMat: partMatKey, mu: muKey, sf, dep,
    // 材料定数
    Sy: gr.Sy, Su: gr.Su,
    // ボルト寸法
    p: b.p, d2: b.d2, As: b.As, dw: b.dw, dh: b.dh,
    // 中間値
    K, Fy,
    // 主要結果
    T_lim,
    T_jis,
    T_rec,
    T_range: { min: +(T_rec * 0.9).toFixed(2), max: +(T_rec * 1.1).toFixed(2) },
    // 破損解析
    failModes,
    dominant: dominant.name,
    isMaterialLimit,
    warnings,
  };
}

const Bolt = {
  BOLTS:              BOLT_DATA,
  GRADES:             BOLT_GRADES,
  CLAMPED_MATERIALS:  CLAMPED_MATERIALS,
  FRICTION:           FRICTION_MAP,

  /**
   * ボルト締付トルク計算（JIS B 1083）。
   * @param {object} params - { d, grade, partMat, mu, sf?, dep? }
   * @returns {BoltResult}
   */
  calc: boltCalc,
};

