toolUseResult.originalFile:
/**
 * verify-mechsense-bolt.js
 * MechSense.Bolt モジュール検証スクリプト
 *
 * 検証基準:
 *   boltsense-mobile.html の calc() と同一入力で同一結果になること
 *   bolt-torque-app/CALCULATION_FORMULAS.md の理論値と一致すること
 *
 * 実行: node verify-mechsense-bolt.js
 */

'use strict';

const MechSense = require('../mechsense-core.js');

let pass = 0;
let fail = 0;

function assert(label, got, expected, tol = 1e-6) {
  if (typeof expected === 'boolean') {
    const ok = got === expected;
    if (ok) { pass++; }
    else    { fail++; console.error(`  FAIL [${label}]  got=${got}  expected=${expected}`); }
    return;
  }
  const diff = Math.abs(got - expected);
  if (diff <= tol) {
    pass++;
  } else {
    fail++;
    console.error(`  FAIL [${label}]  got=${got}  expected=${expected}  diff=${diff}`);
  }
}

function assertStr(label, got, expected) {
  if (got === expected) { pass++; }
  else { fail++; console.error(`  FAIL [${label}]  got="${got}"  expected="${expected}"`); }
}

// ──────────────────────────────────────────────────────
// ケース1: M10 / 10.9 / 鋼 SS400 / 乾燥（基準ケース）
//   boltsense-mobile.html 検証済み値: T_lim=113.40 N·m (CALCULATION_FORMULAS.md 例示)
// ──────────────────────────────────────────────────────
console.log('\n[ケース1] M10 / 10.9 / steel / dry');
{
  const r = MechSense.Bolt.calc({ d: 10, grade: '10.9', partMat: 'steel', mu: 'dry' });
  assert('error=null',  r.error, null);
  assert('K',           r.K,     0.1965, 5e-4);      // 文書値 K≈0.197
  assert('Fy (kN)',     r.Fy,    57.7,   0.5);        // 文書値 Fy≈58 kN
  assert('T_lim (N·m)', r.T_lim, 113.4,  1.0);       // 文書値 113.40 N·m
  assert('T_jis (N·m)', r.T_jis, 75.6,   1.0);       // 113.40/1.5 = 75.60
  assert('T_rec',       r.T_rec, r.T_jis, 1e-9);     // 鋼なのでJIS値がそのまま
  assert('isMaterialLimit', r.isMaterialLimit, false);
  assertStr('dominant',  r.dominant, 'ボルト破断');   // 鋼×10.9はボルト破断が支配
}

// ──────────────────────────────────────────────────────
// ケース2: M8 / 8.8 / アルミ A6061 / 潤滑
//   ソフト材なので被締結材強度による低減が発生するはず
// ──────────────────────────────────────────────────────
console.log('[ケース2] M8 / 8.8 / aluminum / lube（ソフト材制限あり）');
{
  const r = MechSense.Bolt.calc({ d: 8, grade: '8.8', partMat: 'aluminum', mu: 'lube' });
  assert('error=null', r.error, null);
  assert('T_lim > 0',  r.T_lim > 0, true);
  assert('isMaterialLimit', r.isMaterialLimit, true);   // アルミなので制限あり
  assert('T_rec < T_jis',   r.T_rec < r.T_jis, true);
  assert('warnings.length > 0', r.warnings.length > 0, true);
}

// ──────────────────────────────────────────────────────
// ケース3: M6 / 4.6 / SUS304 / グリス
// ──────────────────────────────────────────────────────
console.log('[ケース3] M6 / 4.6 / sus304 / grease');
{
  const r = MechSense.Bolt.calc({ d: 6, grade: '4.6', partMat: 'sus304', mu: 'grease' });
  assert('error=null', r.error, null);
  assert('K > 0',      r.K > 0, true);
  assert('Fy > 0',     r.Fy > 0, true);
  assert('T_lim > 0',  r.T_lim > 0, true);
  assert('T_range.min < T_rec', r.T_range.min < r.T_rec, true);
  assert('T_range.max > T_rec', r.T_range.max > r.T_rec, true);
}

// ──────────────────────────────────────────────────────
// ケース4: M12 / A4-80 / エンプラ / 乾燥
//   エンプラ（resin）は最も軟質 → 座面陥没が支配的になりやすい
// ──────────────────────────────────────────────────────
console.log('[ケース4] M12 / A4-80 / resin / dry（座面陥没）');
{
  const r = MechSense.Bolt.calc({ d: 12, grade: 'A4-80', partMat: 'resin', mu: 'dry' });
  assert('error=null', r.error, null);
  assert('isMaterialLimit', r.isMaterialLimit, true);
  assert('failModes.length', r.failModes.length, 3);
  // failModes は昇順ソート済み
  assert('failModes sorted', r.failModes[0].F <= r.failModes[1].F, true);
  assert('failModes sorted2', r.failModes[1].F <= r.failModes[2].F, true);
}

// ──────────────────────────────────────────────────────
// ケース5: M20 / 12.9 / S45C / 乾燥（大径高強度）
// ──────────────────────────────────────────────────────
console.log('[ケース5] M20 / 12.9 / s45c / dry（大径高強度）');
{
  const r = MechSense.Bolt.calc({ d: 20, grade: '12.9', partMat: 's45c', mu: 'dry' });
  assert('error=null', r.error, null);
  assert('T_lim > 200', r.T_lim > 200, true);          // 大径×高強度なので高トルク
  assert('isMaterialLimit', r.isMaterialLimit, false);   // S45C は硬質材
}

// ──────────────────────────────────────────────────────
// ケース6: T_range の整合性
// ──────────────────────────────────────────────────────
console.log('[ケース6] T_range ±10% 整合性チェック');
{
  const r = MechSense.Bolt.calc({ d: 16, grade: '8.8', partMat: 'steel', mu: 'lube' });
  const expMin = +(r.T_rec * 0.9).toFixed(2);
  const expMax = +(r.T_rec * 1.1).toFixed(2);
  assert('T_range.min', r.T_range.min, expMin);
  assert('T_range.max', r.T_range.max, expMax);
}

// ──────────────────────────────────────────────────────
// ケース7: boltsense-mobile.html との互換性確認（M10/10.9/steel/dry）
//   boltsense-mobile.html の calc() が返す T_rec を手計算で再現
// ──────────────────────────────────────────────────────
console.log('[ケース7] BoltSense mobile.html 互換性確認 M10/10.9/steel/dry');
{
  const b = { p:1.5, d2:9.026, d3:8.376, As:58.0, dw:16.0, dh:11.0 };
  const gr = { Sy:940, Su:1040 };
  const mt = 0.15, mw = 0.15, d = 10, sf = 1.5;

  const Db  = (b.dw + b.dh) / 2;
  const K_ref = b.p / (2 * Math.PI * d) + 0.577 * mt * b.d2 / d + mw * Db / (2 * d);
  const Knd = K_ref * d;
  const At  = b.p / (2 * Math.PI) + 0.577 * mt * b.d2;
  const dAs = Math.sqrt(4 * b.As / Math.PI);
  const Fy_ref = gr.Sy * b.As / Math.sqrt(1 + 3 * Math.pow(3 / dAs * At, 2)) / 1000;
  const T_lim_ref = Knd * Fy_ref;
  const T_jis_ref = T_lim_ref / sf;

  const r = MechSense.Bolt.calc({ d: 10, grade: '10.9', partMat: 'steel', mu: 'dry' });
  assert('K vs bolt-mobile',     r.K,     K_ref,     1e-10);
  assert('Fy vs bolt-mobile',    r.Fy,    Fy_ref,    1e-10);
  assert('T_lim vs bolt-mobile', r.T_lim, T_lim_ref, 1e-10);
  assert('T_jis vs bolt-mobile', r.T_jis, T_jis_ref, 1e-10);
}

// ──────────────────────────────────────────────────────
// エラーケース
// ──────────────────────────────────────────────────────
console.log('[エラーケース] バリデーション');
{
  const r1 = MechSense.Bolt.calc({ d: 99, grade: '10.9', partMat: 'steel', mu: 'dry' });
  assert('unknown diameter → error', r1.error !== null, true);

  const r2 = MechSense.Bolt.calc({ d: 10, grade: 'INVALID', partMat: 'steel', mu: 'dry' });
  assert('unknown grade → error', r2.error !== null, true);

  const r3 = MechSense.Bolt.calc({ d: 10, grade: '10.9', partMat: 'INVALID', mu: 'dry' });
  assert('unknown partMat → error', r3.error !== null, true);

  const r4 = MechSense.Bolt.calc({ d: 10, grade: '10.9', partMat: 'steel', mu: 'INVALID' });
  assert('unknown mu → error', r4.error !== null, true);
}

// ──────────────────────────────────────────────────────
// API 構造チェック
// ──────────────────────────────────────────────────────
console.log('[APIチェック] モジュール構造');
{
  assert('version 1.1.0', MechSense.version === '1.1.0', true);
  assert('Bolt.BOLTS',             typeof MechSense.Bolt.BOLTS === 'object', true);
  assert('Bolt.GRADES',            typeof MechSense.Bolt.GRADES === 'object', true);
  assert('Bolt.CLAMPED_MATERIALS', typeof MechSense.Bolt.CLAMPED_MATERIALS === 'object', true);
  assert('Bolt.FRICTION',          typeof MechSense.Bolt.FRICTION === 'object', true);
  assert('Bolt.calc',              typeof MechSense.Bolt.calc === 'function', true);
}

// ──────────────────────────────────────────────────────
// 結果
// ──────────────────────────────────────────────────────
console.log(`\n${'─'.repeat(50)}`);
console.log(`結果: ${pass} PASS / ${fail} FAIL`);
if (fail === 0) console.log('✅ 全ケース PASS — Bolt モジュール実装は正確');
else            console.log('❌ FAILあり — 実装を確認してください');
process.exit(fail === 0 ? 0 : 1);
